import { useState, useEffect } from "react";
import Message from "./Message";
import Sidebar from "./Sidebar";
import { io } from "socket.io-client";
import "../App.css"; // Make sure CSS supports sidebar layout

const socket = io("http://127.0.0.1:8000/ws" , {
  path: "/ws/socket.io", // <-- important
  transports: ["websocket", "polling"],});

function Chat({ user }) {
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [currentChat, setCurrentChat] = useState(null); // username of recipient
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [typing, setTyping] = useState("");

  // Socket event listeners
  useEffect(() => {
    // Join server
    socket.emit("join", { user });

    // Update online users
    socket.on("online_users", (users) => {
      setOnlineUsers(users.filter(u => u !== user));
    });

    // Receive private messages
    socket.on("receive_private", (msg) => {
      // Only show messages if it's relevant to current chat
      if (msg.sender === currentChat || msg.recipient === currentChat || msg.sender === user) {
        setMessages(prev => [...prev, msg]);
      }
    });

    // Typing indicator
    socket.on("typing", (data) => {
      if (data.sender === currentChat) {
        setTyping(`${data.sender} is typing...`);
        setTimeout(() => setTyping(""), 1500);
      }
    });

    // Cleanup on unmount
    return () => {
      socket.off("receive_private");
      socket.off("typing");
      socket.off("online_users");
    };
  }, [user, currentChat]);

  // Send a private message
  const send = () => {
    if (!text || !currentChat) return;

    const msg = {
      sender: user,
      recipient: currentChat,
      text,
      time: new Date().toLocaleTimeString()
    };

    socket.emit("private_message", msg);
    setMessages(prev => [...prev, msg]);
    setText("");
  };

  // Emit typing event
  const handleTyping = () => {
    if (currentChat) {
      socket.emit("typing", { sender: user, recipient: currentChat });
    }
  };

  return (
    <div className="chat-app">
      {/* Sidebar */}
      <Sidebar
        onlineUsers={onlineUsers}
        currentChat={currentChat}
        setCurrentChat={setCurrentChat}
        user={user}
      />

      {/* Main Chat */}
      <div className="chat-container">
        <div className="chat-box">
          {messages.map((m, i) => (
            <Message key={i} msg={m} user={user} />
          ))}
        </div>

        {typing && <p className="typing">{typing}</p>}

        <div className="chat-input">
          <input
            value={text}
            onChange={e => setText(e.target.value)}
            onKeyPress={handleTyping}
            placeholder={currentChat ? `Message ${currentChat}` : "Select a user to chat"}
            disabled={!currentChat}
          />
          <button onClick={send} disabled={!currentChat}>Send</button>
        </div>
      </div>
    </div>
  );
}

export default Chat;
